import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useSocket } from '../contexts/SocketContext';
import axios from 'axios';
import './Navbar.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const Navbar = () => {
  const { user, logout } = useAuth();
  const { socket } = useSocket();
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    if (user) {
      fetchAllUnreadCounts();
      loadStoredNotifications();
    }
  }, [user]);

  useEffect(() => {
    if (socket && user) {
      // Join user room
      socket.emit('join_user_room', user._id);

      // Listen for rating replies
      socket.on('machine_rating_reply', (data) => {
        if (data.userId === user._id) {
          addNotification({
            type: 'rating_reply',
            title: 'Reply to Your Feedback',
            message: `Admin replied to your ${data.type || 'feedback'}`,
            data: data,
            link: '/customer/ratings'
          });
        }
      });

      // Listen for return status updates
      socket.on('return_status_update', (data) => {
        if (data.userId === user._id) {
          const statusMessage = data.status === 'APPROVED' ? 'approved' : 'rejected';
          addNotification({
            type: 'return_update',
            title: 'Return Request Update',
            message: `Your return request ${data.returnId} has been ${statusMessage}`,
            data: data,
            link: '/customer/returns'
          });
        }
      });

      // Listen for message replies
      socket.on('message_reply_notification', (data) => {
        if (data.userId === user._id) {
          addNotification({
            type: 'message_reply',
            title: 'New Message Reply',
            message: `Admin replied to your message: "${data.subject}"`,
            data: data,
            link: '/customer/messages'
          });
        }
      });

      // Listen for general notifications
      socket.on('notification', (data) => {
        if (data.userId === user._id) {
          addNotification({
            type: data.type || 'general',
            title: data.title || 'New Notification',
            message: data.message,
            data: data.data,
            link: data.link || '/customer/dashboard'
          });
        }
      });

      return () => {
        socket.off('machine_rating_reply');
        socket.off('return_status_update');
        socket.off('message_reply_notification');
        socket.off('notification');
      };
    }
  }, [socket, user]);

  useEffect(() => {
    // Request notification permission
    if (Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);

  const fetchAllUnreadCounts = async () => {
    try {
      // Fetch unread reply counts from different endpoints
      const [ratingRes, returnRes, messageRes] = await Promise.all([
        axios.get(`${API_URL}/ratings/machine/unread-replies`).catch(() => ({ data: { count: 0 } })),
        axios.get(`${API_URL}/returns/unread-updates`).catch(() => ({ data: { count: 0 } })),
        axios.get(`${API_URL}/messages/unread-replies`).catch(() => ({ data: { count: 0 } }))
      ]);

      const total = (ratingRes.data.count || 0) + 
                    (returnRes.data.count || 0) + 
                    (messageRes.data.count || 0);
      
      setUnreadCount(total);
    } catch (error) {
      console.error('Error fetching unread counts:', error);
    }
  };

  const loadStoredNotifications = () => {
    // Load notifications from localStorage
    const stored = localStorage.getItem(`notifications_${user?._id}`);
    if (stored) {
      const parsed = JSON.parse(stored);
      setNotifications(parsed);
      const unread = parsed.filter(n => !n.read).length;
      setUnreadCount(unread);
    }
  };

  const saveNotifications = (updatedNotifications) => {
    localStorage.setItem(`notifications_${user?._id}`, JSON.stringify(updatedNotifications));
  };

  const addNotification = (notification) => {
    const newNotification = {
      id: Date.now(),
      timestamp: new Date().toISOString(),
      read: false,
      ...notification
    };

    setNotifications(prev => {
      const updated = [newNotification, ...prev].slice(0, 50); // Keep last 50
      saveNotifications(updated);
      return updated;
    });

    setUnreadCount(prev => prev + 1);

    // Show browser notification
    if (Notification.permission === 'granted') {
      new Notification(notification.title || 'New Notification', {
        body: notification.message,
        icon: '/logo192.png',
        tag: notification.type
      });
    }
  };

  const markAsRead = async (notification) => {
    // Mark as read in UI
    const updatedNotifications = notifications.map(n =>
      n.id === notification.id ? { ...n, read: true } : n
    );
    setNotifications(updatedNotifications);
    saveNotifications(updatedNotifications);
    
    const newUnreadCount = updatedNotifications.filter(n => !n.read).length;
    setUnreadCount(newUnreadCount);

    // Mark as seen in backend based on type
    try {
      if (notification.type === 'rating_reply' && notification.data?.ratingId) {
        await axios.put(`${API_URL}/ratings/machine/${notification.data.ratingId}/mark-seen`);
      } else if (notification.type === 'return_update' && notification.data?.returnId) {
        await axios.put(`${API_URL}/returns/${notification.data.returnId}/mark-seen`);
      } else if (notification.type === 'message_reply' && notification.data?.messageId) {
        await axios.put(`${API_URL}/messages/${notification.data.messageId}/mark-seen`);
      }
    } catch (error) {
      console.error('Error marking as seen:', error);
    }
  };

  const markAllAsRead = async () => {
    const updatedNotifications = notifications.map(n => ({ ...n, read: true }));
    setNotifications(updatedNotifications);
    saveNotifications(updatedNotifications);
    setUnreadCount(0);

    // In a real app, you'd want to call a bulk update endpoint
  };

  const clearAllNotifications = () => {
    setNotifications([]);
    setUnreadCount(0);
    localStorage.removeItem(`notifications_${user?._id}`);
  };

  const getNotificationIcon = (type) => {
    switch(type) {
      case 'rating_reply': return '⭐';
      case 'return_update': return '↩️';
      case 'message_reply': return '💬';
      default: return '🔔';
    }
  };

  const getTimeAgo = (timestamp) => {
    const now = new Date();
    const then = new Date(timestamp);
    const diffMs = now - then;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays < 7) return `${diffDays}d ago`;
    return then.toLocaleDateString();
  };

  return (
    <nav className="navbar">
      <div className="navbar-container">
        <Link to="/" className="navbar-logo">
          <span className="logo-icon">🌾</span>
          <span className="logo-text">AgriVend</span>
        </Link>

        <div className="navbar-actions">
          {/* Notifications Bell */}
          <div className="notification-wrapper">
            <button 
              className="notification-btn"
              onClick={() => setShowNotifications(!showNotifications)}
              aria-label="Notifications"
            >
              <span className="notification-icon">🔔</span>
              {unreadCount > 0 && (
                <span className="notification-badge">{unreadCount}</span>
              )}
            </button>

            {/* Notifications Dropdown */}
            {showNotifications && (
              <div className="notifications-dropdown">
                <div className="notifications-header">
                  <div>
                    <h3>Notifications</h3>
                    <span className="notification-count">
                      {unreadCount} unread
                    </span>
                  </div>
                  <div className="header-actions">
                    {notifications.length > 0 && (
                      <>
                        <button onClick={markAllAsRead} className="mark-all-read" title="Mark all as read">
                          ✓ All
                        </button>
                        <button onClick={clearAllNotifications} className="clear-all" title="Clear all">
                          ✗ Clear
                        </button>
                      </>
                    )}
                  </div>
                </div>

                <div className="notifications-list">
                  {notifications.length === 0 ? (
                    <div className="no-notifications">
                      <span className="empty-icon">🔔</span>
                      <p>No notifications yet</p>
                    </div>
                  ) : (
                    notifications.map((notification) => (
                      <Link
                        key={notification.id}
                        to={notification.link || '#'}
                        className={`notification-item ${!notification.read ? 'unread' : ''}`}
                        onClick={() => {
                          markAsRead(notification);
                          setShowNotifications(false);
                        }}
                      >
                        <div className="notification-icon-wrapper">
                          {getNotificationIcon(notification.type)}
                        </div>
                        <div className="notification-content">
                          <h4 className="notification-title">{notification.title}</h4>
                          <p className="notification-message">{notification.message}</p>
                          <span className="notification-time">
                            {getTimeAgo(notification.timestamp)}
                          </span>
                        </div>
                        {!notification.read && <span className="unread-dot" />}
                      </Link>
                    ))
                  )}
                </div>

                {notifications.length > 0 && (
                  <div className="notifications-footer">
                    <Link 
                      to="/customer/notifications" 
                      onClick={() => setShowNotifications(false)}
                    >
                      View all notifications
                    </Link>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* User Menu */}
          <div className="user-menu">
            <span className="user-name">
              {user?.firstName} {user?.lastName}
            </span>
            <button onClick={logout} className="logout-btn-nav">
              Logout
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
